<!DOCTYPE html>
<html>
<head>
  <title>Falling Sand Simulation</title>
  <style>
    body {
      background-color: #1e1e1e;
      display: flex;
      justify-content: center;
      align-items: center;
      height: 100vh;
      margin: 0;
      font-family: sans-serif;
    }

    #container {
      width: 800px;
      height: 600px;
      position: relative;
    }

    #canvas {
      background-color: #282c34;
      border: none;
      display: block;
    }

    .button {
      background-color: #3e4451;
      color: white;
      padding: 10px 20px;
      border: none;
      cursor: pointer;
      margin: 5px;
      font-size: 16px;
    }

    .button:hover {
      background-color: #434c5e;
    }
  </style>
</head>
<body>
  <div id="container">
    <h1>Falling Sand</h1>
    <canvas id="canvas"></canvas>
    <div>
      <button class="button" id="mat-sand">Sand</button>
      <button class="button" id="mat-water">Water</button>
      <button class="button" id="mat-wall">Wall</button>
      <button class="button" id="mat-acid">Acid</button>
      <button class="button" id="mat-empty">Empty (Eraser)</button>
      <button class="button" id="clear">Clear</button>
    </div>
  </div>

  <script>
    const w = 80;
    const h = 60;
    const cellSize = 20;
    const canvasWidth = w * cellSize;
    const canvasHeight = h * cellSize;

    const canvas = document.getElementById('canvas');
    canvas.width = canvasWidth;
    canvas.height = canvasHeight;
    const ctx = canvas.getContext('2d');

    let grid = [];
    for (let y = 0; y < h; y++) {
      grid[y] = [];
      for (let x = 0; x < w; x++) {
        grid[y][x] = 'empty';
      }
    }

    let isDragging = false;
    let dragX = null;
    let dragY = null;
    let currentMaterial = 'sand'; // Default material

    canvas.addEventListener('mousedown', (e) => {
      const x = Math.floor(e.offsetX / cellSize);
      const y = Math.floor(e.offsetY / cellSize);

      if (x >= 0 && x < w && y >= 0 && y < h) {
        isDragging = true;
        dragX = x;
        dragY = y;
        currentMaterial = e.target.id; // Get the material from the button clicked
      }
    });

    canvas.addEventListener('mouseup', () => {
      isDragging = false;
      dragX = null;
      dragY = null;
    });

    canvas.addEventListener('mousemove', (e) => {
      if (!isDragging) return;

      const x = Math.floor(e.offsetX / cellSize);
      const y = Math.floor(e.offsetY / cellSize);

      if (x >= 0 && x < w && y >= 0 && y < h) {
        grid[y][x] = currentMaterial;
      }
    });


    window.sim = {
      w,
      h,
      tick(n) {
        for (let i = 0; i < n; i++) {
          simulate();
        }
      },
      get(x, y) {
        if (x >= 0 && x < w && y >= 0 && y < h) {
          return grid[y][x];
        }
        return 'empty';
      },
      set(x, y, material) {
        if (x >= 0 && x < w && y >= 0 && y < h) {
          grid[y][x] = material;
        }
      },
      clear() {
        for (let y = 0; y < h; y++) {
          for (let x = 0; x < w; x++) {
            grid[y][x] = 'empty';
          }
        }
      }
    };

    function simulate() {
      const newGrid = grid.map(row => [...row]); // Deep copy

      for (let y = h - 1; y >= 0; y--) {
        for (let x = 0; x < w; x++) {
          const cell = grid[y][x];

          if (cell === 'empty') {
            // Try to place material
            let placed = false;
            for (const mat of ['sand', 'water', 'wall', 'acid']) {
              if (mat !== currentMaterial) { // Don't overwrite the currently dragged material
                if (canPlace(x, y, mat)) {
                  newGrid[y][x] = mat;
                  placed = true;
                  break;
                }
              }
            }
            if (!placed) {
              newGrid[y][x] = 'empty'; // Remain empty if no material can be placed
            }
          } else if (cell === 'sand') {
            // Sand falls down
            let nextY = y + 1;
            if (nextY < h && newGrid[nextY][x] === 'empty') {
              newGrid[nextY][x] = 'sand';
            } else {
              // Sand slides diagonally down-left/right
              const dir = Math.random() < 0.5 ? -1 : 1;
              let nextX = x + dir;
              if (nextX >= 0 && nextX < w && newGrid[y][nextX] === 'empty') {
                newGrid[y][nextX] = 'sand';
              }
            }
          } else if (cell === 'water') {
            // Water falls like sand
            let nextY = y + 1;
            if (nextY < h && newGrid[nextY][x] === 'empty') {
              newGrid[nextY][x] = 'water';
            } else {
              // Water spreads horizontally
              let nextX = x;
              while (nextX < w && newGrid[y][nextX] === 'empty') {
                newGrid[y][nextX] = 'water';
                nextX++;
              }
            }
          } else if (cell === 'acid') {
            // Acid moves like water and dissolves
            let nextY = y + 1;
            if (nextY < h && newGrid[nextY][x] === 'empty') {
              newGrid[nextY][x] = 'water'; // Water spreads
            } else {
              // Acid dissolves sand/wall
              const directions = [[-1, 0], [1, 0], [0, -1], [0, 1]];
              for (const [dx, dy] of directions) {
                const nextX = x + dx;
                const nextY = y + dy;
                if (nextX >= 0 && nextX < w && nextY >= 0 && nextY < h) {
                  const neighbor = newGrid[nextY][nextX];
                  if (neighbor === 'sand' || neighbor === 'wall') {
                    newGrid[nextY][nextX] = 'empty'; // Dissolve
                  }
                }
              }
            }
          } else if (cell === 'wall') {
            // Walls don't move
          }
        }
      }

      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          grid[y][x] = newGrid[y][x];
        }
      }
    }

    function canPlace(x, y, material) {
      if (material === 'sand' && (y > 0 && grid[y - 1][x] !== 'empty')) return false;
      if (material === 'water' && (y > 0 && grid[y - 1][x] !== 'empty')) return false;
      if (material === 'acid' && (y > 0 && grid[y - 1][x] !== 'empty')) return false;

      return true;
    }


    // Initial setup (optional)
    window.sim.set(0, 0, 'sand');
    window.sim.set(1, 0, 'sand');
    window.sim.set(2, 0, 'sand');
  </script>
</body>
</html>
